mapper.select:
/* ====== cmn.authmgmt.prgmList =========*/ SELECT a.PRGM_ID , a.MENU_ID , a.PRGM_NM , a.PRGM_DESC , a.PRGM_URL , a.USG_YN , a.REGST_ID , TO_CHAR(a.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') REGST_DTTM , a.RVISN_ID , TO_CHAR(a.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') RVISN_DTTM , a.PRGM_TYPE , DECODE(a.PRGM_TYPE, 'MAIN','메인', 'SRCH','검색','CREAT','등록','RVISN','변경','DEL','삭제','EXEL','엑셀','PRNT','출력','ETC','기타') PRGM_TYPE_STRING , a.UPPR_PRGM_ID , B.MENU_NM_HGHR FROM CMN_PRGM_MST a, ( SELECT ROWNUM ROW_INDEX , a.MENU_ID , replace(RPAD(' ', 4*(LEVEL - 1)),' ','.') || MENU_NM MENU_NM_HGHR FROM CMN_MENU_MST a START WITH '0' = a.MENU_LVL CONNECT BY a.HGHR_MENU_ID = PRIOR a.MENU_ID ORDER SIBLINGS BY 1 + ALGN_SEQ ) b WHERE 1 = 1 AND A.MENU_ID = B.MENU_ID(+)
AND a.MENU_ID = #{MENU_ID}
ORDER BY B.ROW_INDEX

/* ====== cmn.authmgmt.prgmList2 =========*/ SELECT PRGM_ID ,MENU_ID ,PRGM_NM ,PRGM_DESC ,PRGM_URL ,USG_YN ,REGST_ID ,REGST_DTTM ,RVISN_ID ,RVISN_DTTM ,PRGM_TYPE ,UPPR_PRGM_ID , DECODE(PRGM_TYPE, 'MAIN','메인', 'SRCH','검색','CREAT','등록','RVISN','변경','DEL','삭제','EXEL','엑셀','PRNT','출력','ETC','기타') PRGM_TYPE_STRING FROM CMN_PRGM_MST WHERE 1=1
AND UPPER(PRGM_ID) LIKE '%' || UPPER(#{PRGM_ID}) || '%'
AND UPPER(PRGM_NM) LIKE '%' || UPPER(#{PRGM_NM}) || '%'
AND PRGM_TYPE = #{PRGM_TYPE}
AND USG_YN = #{USG_YN}
ORDER BY MENU_ID ASC, PRGM_NM ASC

