      , PRGM_URL          
      , USG_YN            
      , REGST_ID          
      , REGST_DTTM        
      , RVISN_ID          
      , RVISN_DTTM      
      , PRGM_TYPE   
	  , UPPR_PRGM_ID      
	)
	VALUES
	( 
        #{PRGM_ID         }
      , #{MENU_ID         }
      , #{PRGM_NM         }
      , #{PRGM_DESC       }
      , #{PRGM_URL        }
      , NVL(#{USG_YN      },'N')
      , #{SESSION_USER_ID }
      , SYSDATE
      , #{SESSION_USER_ID }
      , SYSDATE
      , #{PRGM_TYPE       }
      , #{UPPR_PRGM_ID       }
	)

