/* ====== cmn.authmgmt.menuHghrList =========*/
SELECT a.* FROM ( SELECT ROWNUM ROW_INDEX , a.MENU_ID , a.MENU_LVL , a.MENU_NM , replace(RPAD(' ', 4*(LEVEL - 1)),' ','.') || MENU_NM MENU_NM_HGHR , a.MENU_DSC , a.HGHR_MENU_ID , a.ALGN_SEQ , a.USG_YN , a.LMT_ORGN_LVL_CD , a.REGST_ID , TO_CHAR(a.REG_DTTM, 'YYYY-MM-DD HH24:MI:SS') REG_DTTM , a.RVISN_ID , TO_CHAR(a.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') RVISN_DTTM , a.DUTY_NM , a.DEL_YN , a.PRGM_ID , a.DUTY_ID FROM CMN_MENU_MST a START WITH '0' = a.MENU_LVL CONNECT BY a.HGHR_MENU_ID = PRIOR a.MENU_ID ORDER SIBLINGS BY 1 + ALGN_SEQ ) a WHERE 1 = 1
AND a.MENU_NM like '%' || #{searchMenuNm} || '%'
AND a.MENU_LVL = #{searchMenuLvl}
ORDER BY ROW_INDEX

