/* ====== cmn.authmgmt.authMenuList =========*/
SELECT a.AUTH_ID , a.MENU_ID , a.CREAT_ABABLE_YN , a.DEL_AUTH , a.RVISN_AUTH , a.SRCH_AUTH , a.EXEL_ABABLE_YN , a.PRNT_ABABLE_YN , a.REGST_ID , TO_CHAR(a.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') REGST_DTTM , a.RVISN_ID , TO_CHAR(a.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') RVISN_DTTM
, B.MENU_LVL , trim(replace(C.MENU_NM_PATH,' > >','')) MENU_NM FROM CMN_AUTH_MENU_ASGN_MST a, CMN_MENU_MST B, ( SELECT ROWNUM ROW_INDEX , a.MENU_ID ,SYS_CONNECT_BY_PATH(decode(level,0, '', 1,'', a.MENU_NM), ' > ') MENU_NM_PATH FROM CMN_MENU_MST a START WITH '0' = a.MENU_LVL CONNECT BY a.HGHR_MENU_ID = PRIOR a.MENU_ID ORDER SIBLINGS BY 1 + ALGN_SEQ ) C WHERE 1 = 1 AND A.MENU_ID = B.MENU_ID AND A.MENU_ID = C.MENU_ID
AND a.AUTH_ID = #{AUTH_ID}
AND a.MENU_ID = #{MENU_ID}

