/* ====== cmn.authmgmt.usrMenuAsgnList =========*/
SELECT a.USR_ID , a.USR_ID AS USR_ID_MSK , a.MENU_ID , a.CREAT_ABABLE_YN , a.DEL_AUTH , a.RVISN_AUTH , a.SRCH_AUTH , a.EXEL_ABABLE_YN , a.PRNT_ABABLE_YN , a.REGST_ID , a.REGST_DTTM , a.RVISN_ID , a.RVISN_DTTM , b.USR_NM
, trim(replace(d.MENU_NM_PATH,' > >','')) MENU_NM FROM CMN_USR_MENU_ASGN_MST a, CMN_USR_MST B,
( SELECT ROWNUM ROW_INDEX , a.MENU_ID ,SYS_CONNECT_BY_PATH(decode(level,0, '', 1,'', a.MENU_NM), ' > ') MENU_NM_PATH FROM CMN_MENU_MST a START WITH '0' = a.MENU_LVL CONNECT BY a.HGHR_MENU_ID = PRIOR a.MENU_ID ORDER SIBLINGS BY 1 + ALGN_SEQ ) d WHERE 1 = 1 AND A.USR_ID = B.USR_ID
AND A.MENU_ID = d.MENU_ID
AND a.MENU_ID = #{MENU_ID}
AND a.USR_ID = #{USR_ID}
ORDER BY d.ROW_INDEX

