/* ====== cmn.authmgmt.usrGrpAsgnList =========*/
SELECT a.USR_ID , a.USR_ID AS USR_ID_MSK , a.GRP_ID , a.REGST_ID , a.REGST_DTTM , a.RVISN_ID , a.RVISN_DTTM , C.ORGN_NM , b.USR_NM FROM CMN_USG_GRP_ASGN_MST a , CMN_USR_MST b , ORG_ORGN_INFO_MST C WHERE 1 = 1 AND a.USR_ID = b.USR_ID(+) AND B.ORGN_ID = C.ORGN_ID(+) AND B.USG_YN <> 'N'
AND a.GRP_ID = #{GRP_ID}
AND a.USR_ID = #{USR_ID}
ORDER BY C.ORGN_NM, a.USR_ID

