mapper.select:
SELECT A.*, NVL(LAG(MENU_LVL ) OVER( ORDER BY ROW_INDEX ),-1) MENU_LVL_PREV FROM ( SELECT ROWNUM ROW_INDEX , A.MENU_ID ID , A.MENU_ID MENU_ID , A.MENU_LVL || '' MENU_LVL , A.MENU_NM , A.MENU_DSC , A.HGHR_MENU_ID , A.ALGN_SEQ , A.USG_YN , A.LMT_ORGN_LVL_CD , A.DUTY_NM , A.DEL_YN , A.DUTY_ID , B.PRGM_ID , B.PRGM_NM , B.PRGM_DESC , B.PRGM_URL URL , B.PRGM_TYPE , CASE WHEN (SELECT COUNT(*) FROM CMN_MENU_MST WHERE HGHR_MENU_ID = A.MENU_ID) > 0 THEN 'true' ELSE 'false' END XMLKIDS_BO FROM CMN_MENU_MST A, CMN_PRGM_MST B WHERE A.MENU_ID = B.MENU_ID(+) AND ( A.DEL_YN IS NULL OR A.DEL_YN = 'N') AND B.PRGM_TYPE(+) = 'MAIN' ) A WHERE 1=1
AND a.MENU_NM like '%' || #{searchMenuNm} || '%'
AND a.MENU_LVL = #{searchMenuLvl}
AND A.HGHR_MENU_ID = #{menuId}
AND A.MENU_LVL = 0
ORDER by A.ALGN_SEQ ASC, MENU_LVL ASC
